function candidate(target, collection, compare, bias) {
  if (collection.length === 0) {
    return -1;
  }

  const wantsUpper = bias == 2 || bias === "LEAST_UPPER_BOUND" || bias === "least-upper-bound";
  let left = -1;
  let right = collection.length;
  let found = -1;

  while (right - left > 1) {
    const middle = left + Math.floor((right - left) / 2);
    const order = compare(target, collection[middle], true);

    if (order === 0) {
      found = middle;
      break;
    }

    if (order > 0) {
      left = middle;
    } else {
      right = middle;
    }
  }

  let result = found;
  if (result < 0) {
    result = wantsUpper ? right : left;
  }

  if (result < 0 || result >= collection.length) {
    return -1;
  }

  while (result > 0 && compare(collection[result], collection[result - 1], true) === 0) {
    result -= 1;
  }

  return result;
}
